#!/usr/bin/env python3
"""Verify the self-signed TLS certificate."""
import sys
from datetime import datetime

CERT_PATH = "/app/ssl/server.crt"


def load_cert():
    try:
        from cryptography import x509
        from cryptography.hazmat.backends import default_backend
        with open(CERT_PATH, "rb") as f:
            return x509.load_pem_x509_certificate(f.read(), default_backend())
    except ImportError:
        return None


def main():
    import os
    if not os.path.exists(CERT_PATH):
        print(f"ERROR: certificate not found at {CERT_PATH}")
        sys.exit(1)

    cert = load_cert()
    if cert is not None:
        cn = cert.subject.get_attributes_for_oid(
            __import__("cryptography").x509.NameOID.COMMON_NAME
        )[0].value
        try:
            expires = cert.not_valid_after_utc
        except AttributeError:
            expires = cert.not_valid_after
        print(f"Common Name: {cn}")
        print(f"Expiration Date: {expires.strftime('%Y-%m-%d')}")
    else:
        # Fallback to openssl CLI
        import subprocess
        subj = subprocess.check_output(
            ["openssl", "x509", "-in", CERT_PATH, "-noout", "-subject"]
        ).decode()
        cn = subj.split("CN")[-1].split("=")[-1].strip()
        enddate = subprocess.check_output(
            ["openssl", "x509", "-in", CERT_PATH, "-noout", "-enddate"]
        ).decode().split("=", 1)[1].strip()
        dt = datetime.strptime(enddate, "%b %d %H:%M:%S %Y %Z")
        print(f"Common Name: {cn}")
        print(f"Expiration Date: {dt.strftime('%Y-%m-%d')}")

    print("Certificate verification successful")


if __name__ == "__main__":
    main()
